const map = L.map('map').setView([brc_lat, brc_lng], 14);

map.attributionControl.setPrefix("<a href='https://leafletjs.com' title='A JavaScript library for interactive maps'>Leaflet</a>")

L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
    maxZoom: 19,
    attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
}).addTo(map);

const googleMapsUrlBRC = `https://www.google.com/maps/search/?api=1&query=${brc_lat},${brc_lng}`;
const googleMapsUrlHF = `https://www.google.com/maps/search/?api=1&query=${hotel_forras_lat},${hotel_forras_lng}`;
const googleMapsUrlHA = `https://www.google.com/maps/search/?api=1&query=${hotel_art_lat},${hotel_art_lng}`;
const googleMapsUrlHS = `https://www.google.com/maps/search/?api=1&query=${hotel_science_lat},${hotel_science_lng}`;

L.marker([brc_lat, brc_lng])
    .addTo(map)
    .bindPopup(`
      <strong>BRC</strong><br>
      <a href="${googleMapsUrlBRC}" target="_blank" rel="noopener">
        Open in Google Maps
      </a>
    `);

L.marker([hotel_forras_lat, hotel_forras_lng], {icon: hotel_icon_blue})
    .addTo(map)
    .bindPopup(`
      <strong>Hungest Hotel Forrás</strong><br>
      <a href="${googleMapsUrlHF}" target="_blank" rel="noopener">
        Open in Google Maps
      </a>
    `);
    
L.marker([hotel_art_lat, hotel_art_lng], {icon: hotel_icon_orange})
    .addTo(map)
    .bindPopup(`
      <strong>Art Hotel</strong><br>
      <a href="${googleMapsUrlHA}" target="_blank" rel="noopener">
        Open in Google Maps
      </a>
    `);
    
L.marker([hotel_science_lat, hotel_science_lng], {icon: hotel_icon_green})
    .addTo(map)
    .bindPopup(`
      <strong>Science Hotel</strong><br>
      <a href="${googleMapsUrlHS}" target="_blank" rel="noopener">
        Open in Google Maps
      </a>
    `);
